__global__ void fused_matmul(float* A, float* B, float* C, int M, int N, int K) {
    int row_base = (blockIdx.y * blockDim.y + threadIdx.y) * 4;
    int col_base = (blockIdx.x * blockDim.x + threadIdx.x) * 4;
    __shared__ float As[4128];
    int sr0 = threadIdx.y * 4;
    int sr1 = sr0 + 1;
    int sr2 = sr0 + 2;
    int sr3 = sr0 + 3;
    float acc00 = 0.0f;
    float acc01 = 0.0f;
    float acc02 = 0.0f;
    float acc03 = 0.0f;
    float acc10 = 0.0f;
    float acc11 = 0.0f;
    float acc12 = 0.0f;
    float acc13 = 0.0f;
    float acc20 = 0.0f;
    float acc21 = 0.0f;
    float acc22 = 0.0f;
    float acc23 = 0.0f;
    float acc30 = 0.0f;
    float acc31 = 0.0f;
    float acc32 = 0.0f;
    float acc33 = 0.0f;
    for (int tile_k = 0; tile_k < K; tile_k += 128) {
        for (int a_s = threadIdx.x; a_s < 128; a_s += 32) {
            As[sr0 * 129 + a_s] = ((row_base + 0 < M && tile_k + a_s < K) ? (A[(row_base + 0) * K + (tile_k + a_s)]) : (0.0f));
            As[sr1 * 129 + a_s] = ((row_base + 1 < M && tile_k + a_s < K) ? (A[(row_base + 1) * K + (tile_k + a_s)]) : (0.0f));
            As[sr2 * 129 + a_s] = ((row_base + 2 < M && tile_k + a_s < K) ? (A[(row_base + 2) * K + (tile_k + a_s)]) : (0.0f));
            As[sr3 * 129 + a_s] = ((row_base + 3 < M && tile_k + a_s < K) ? (A[(row_base + 3) * K + (tile_k + a_s)]) : (0.0f));
        }
        __syncthreads();
        if (col_base + 3 < N && N % 4 == 0) {
            #pragma unroll
            for (int kk = 0; kk < 128; kk++) {
                float a0 = As[sr0 * 129 + kk];
                float a1 = As[sr1 * 129 + kk];
                float a2 = As[sr2 * 129 + kk];
                float a3 = As[sr3 * 129 + kk];
                float4 b4 = *reinterpret_cast<float4*>(&B[(tile_k + kk) * N + col_base]);
                acc00 += a0 * b4.x;
                acc01 += a0 * b4.y;
                acc02 += a0 * b4.z;
                acc03 += a0 * b4.w;
                acc10 += a1 * b4.x;
                acc11 += a1 * b4.y;
                acc12 += a1 * b4.z;
                acc13 += a1 * b4.w;
                acc20 += a2 * b4.x;
                acc21 += a2 * b4.y;
                acc22 += a2 * b4.z;
                acc23 += a2 * b4.w;
                acc30 += a3 * b4.x;
                acc31 += a3 * b4.y;
                acc32 += a3 * b4.z;
                acc33 += a3 * b4.w;
            }
        } else {
            if (col_base < N) {
                for (int kk = 0; kk < 128; kk++) {
                    float a0 = As[sr0 * 129 + kk];
                    float a1 = As[sr1 * 129 + kk];
                    float a2 = As[sr2 * 129 + kk];
                    float a3 = As[sr3 * 129 + kk];
                    if (col_base + 0 < N) {
                        float bv0 = B[(tile_k + kk) * N + (col_base + 0)];
                        acc00 += a0 * bv0;
                        acc10 += a1 * bv0;
                        acc20 += a2 * bv0;
                        acc30 += a3 * bv0;
                    }
                    if (col_base + 1 < N) {
                        float bv1 = B[(tile_k + kk) * N + (col_base + 1)];
                        acc01 += a0 * bv1;
                        acc11 += a1 * bv1;
                        acc21 += a2 * bv1;
                        acc31 += a3 * bv1;
                    }
                    if (col_base + 2 < N) {
                        float bv2 = B[(tile_k + kk) * N + (col_base + 2)];
                        acc02 += a0 * bv2;
                        acc12 += a1 * bv2;
                        acc22 += a2 * bv2;
                        acc32 += a3 * bv2;
                    }
                    if (col_base + 3 < N) {
                        float bv3 = B[(tile_k + kk) * N + (col_base + 3)];
                        acc03 += a0 * bv3;
                        acc13 += a1 * bv3;
                        acc23 += a2 * bv3;
                        acc33 += a3 * bv3;
                    }
                }
            }
        }
        __syncthreads();
    }
    if (row_base + 0 < M && col_base + 0 < N) {
        C[(row_base + 0) * N + (col_base + 0)] = acc00;
    }
    if (row_base + 0 < M && col_base + 1 < N) {
        C[(row_base + 0) * N + (col_base + 1)] = acc01;
    }
    if (row_base + 0 < M && col_base + 2 < N) {
        C[(row_base + 0) * N + (col_base + 2)] = acc02;
    }
    if (row_base + 0 < M && col_base + 3 < N) {
        C[(row_base + 0) * N + (col_base + 3)] = acc03;
    }
    if (row_base + 1 < M && col_base + 0 < N) {
        C[(row_base + 1) * N + (col_base + 0)] = acc10;
    }
    if (row_base + 1 < M && col_base + 1 < N) {
        C[(row_base + 1) * N + (col_base + 1)] = acc11;
    }
    if (row_base + 1 < M && col_base + 2 < N) {
        C[(row_base + 1) * N + (col_base + 2)] = acc12;
    }
    if (row_base + 1 < M && col_base + 3 < N) {
        C[(row_base + 1) * N + (col_base + 3)] = acc13;
    }
    if (row_base + 2 < M && col_base + 0 < N) {
        C[(row_base + 2) * N + (col_base + 0)] = acc20;
    }
    if (row_base + 2 < M && col_base + 1 < N) {
        C[(row_base + 2) * N + (col_base + 1)] = acc21;
    }
    if (row_base + 2 < M && col_base + 2 < N) {
        C[(row_base + 2) * N + (col_base + 2)] = acc22;
    }
    if (row_base + 2 < M && col_base + 3 < N) {
        C[(row_base + 2) * N + (col_base + 3)] = acc23;
    }
    if (row_base + 3 < M && col_base + 0 < N) {
        C[(row_base + 3) * N + (col_base + 0)] = acc30;
    }
    if (row_base + 3 < M && col_base + 1 < N) {
        C[(row_base + 3) * N + (col_base + 1)] = acc31;
    }
    if (row_base + 3 < M && col_base + 2 < N) {
        C[(row_base + 3) * N + (col_base + 2)] = acc32;
    }
    if (row_base + 3 < M && col_base + 3 < N) {
        C[(row_base + 3) * N + (col_base + 3)] = acc33;
    }
}
